Use **`WebApplicationFactory<TEntryPoint>`** from `Microsoft.AspNetCore.Mvc.Testing`. It hosts your app in-memory and gives you an `HttpClient` — no real port, no real server.

### Setup

```bash
dotnet add tests/MyMcp.Tests package Microsoft.AspNetCore.Mvc.Testing
```

### Example test

```csharp
using Microsoft.AspNetCore.Mvc.Testing;
using System.Net.Http.Json;
using System.Text.Json;

public class McpIntegrationTests
    : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                clientInfo = new { name = "test-client", version = "1.0" },
                capabilities = new { }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2025-03-26",
            body.GetProperty("result")
                .GetProperty("protocolVersion")
                .GetString());
    }

    [Fact]
    public async Task ToolsCall_ReturnsExpectedResult()
    {
        // Initialize first (required by MCP)
        await InitializeAsync();

        var request = new
        {
            jsonrpc = "2.0",
            id = 2,
            method = "tools/call",
            @params = new
            {
                name = "my-tool",
                arguments = new { input = "hello" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var content = body.GetProperty("result")
                         .GetProperty("content")[0];
        Assert.Equal("text", content.GetProperty("type").GetString());
    }

    private async Task InitializeAsync() { /* send initialize as above */ }
}
```

### Key points

| Technique | Why |
|---|---|
| `WebApplicationFactory<Program>` | Hosts your full ASP.NET pipeline in-memory (middleware, DI, routing — everything) |
| `factory.CreateClient()` | Returns an `HttpClient` wired to the in-memory server |
| `factory.WithWebHostBuilder(b => ...)` | Override services (e.g., swap a real DB for an in-memory one) |
| `IClassFixture<>` | Shares the factory across tests in the class for speed |

### Customizing DI for tests

```csharp
var factory = new WebApplicationFactory<Program>()
    .WithWebHostBuilder(builder =>
    {
        builder.ConfigureServices(services =>
        {
            // Replace a real dependency with a fake
            services.AddSingleton<IMyService, FakeMyService>();
        });
    });
```

This runs your **real middleware pipeline and MCP routing** — you're testing the actual HTTP+JSON-RPC contract end-to-end, just without a network socket.
